import React, { useState } from "react";

export default function QuestionStep({ dimension, onComplete }) {
  const [answered, setAnswered] = useState(false);
  const [result, setResult] = useState(null);

  const handleAnswer = (value) => {
    setResult(value);
    setAnswered(true);
  };

  if (answered) {
    return (
      <div className="test-card">
        <img
          src={`/images/${result}.png`}
          alt={result}
          style={{ maxWidth: "150px", marginBottom: "20px" }}
        />

        <p style={{ marginBottom: "30px" }}>
          {dimension.descriptions[result]}
        </p>

        <button onClick={() => onComplete(result)}>
          განაგრძე →
        </button>
      </div>
    );
  }

  const question = dimension.questions[0];

  return (
    <div className="test-card">
      {/* სათაური */}
      <h2>{dimension.title}</h2>

      {/* განმარტება */}
      <p
        style={{
          fontSize: "15px",
          lineHeight: "1.6",
          color: "#b0bec5",
          marginBottom: "26px"
        }}
      >
        {dimension.intro}
      </p>

      {/* კითხვა */}
      <p>{question.text}</p>

      <div style={{ display: "flex", gap: "20px", marginTop: "22px" }}>
        <button onClick={() => handleAnswer(question.a.value)}>
          {question.a.text}
        </button>
        <button onClick={() => handleAnswer(question.b.value)}>
          {question.b.text}
        </button>
      </div>
    </div>
  );
}
